var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"으음......","JPN":"ううん……","ENG":"Hmm...","TWN":"唔……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"더 내려갈 데가 없네요. 여기가 제일 아래층인가 봐요.","JPN":"これ以上下りるところはないようですね。ここが一番下の階みたいです。","ENG":"We can't go down any further. This must be the bottom floor.","TWN":"不能再往下走了。這裡好像是最後一層。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"괜히 내려왔군. 위층과 다르게 이터니움은커녕 잡동사니 하나 없어.","JPN":"無駄だったな。上の階と違ってエタニウムどころか、がらくた一つすらない。","ENG":"Looks like we came down here for nothing. Unlike upstairs, there's hardly a piece of junk down here, let alone Eternium.","TWN":"白下來了。跟上層不同，別說永恆之金了，連個雜物都沒有。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"다시 돌아갈까요? 길이 닫히기 전에 돌아가야 한다고 들었어요.","JPN":"戻りますか？　道が閉ざされる前に戻らなければならないと聞きました。","ENG":"Should we go back up? I heard we have to get back before the path closes.","TWN":"要回去嗎？聽說要在通道關閉之前回去。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"위에 이터니움이 무지 많았으니까, 전부 실으려면 저희도 도와야 할 거예요!","JPN":"上はエタニウムが山ほどあったから、すべて運ぶんだったら私たちも手伝わないと！","ENG":"There's tons of Eternium up there. They'll probably need our help loading it all up!","TWN":"上面的永恆之金那麼多，要全部裝上的話我們也要幫忙才行呢！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그런데 언니, 정말로 여기서 얻은 이터니움이랑 아티팩트까지 전부 가져갈 거예요?","JPN":"でもリタお姉ちゃん、本当にここで手にしたエタニウムとアーティファクトを全部うちの会社に持って帰るんですか？","ENG":"By the way, are you really going to take all the Eternium and Artifacts from here?","TWN":"但是姐姐，真的要把這裡的永恆之金和人造神器全部拿走嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"윌버는 그 정도 협박은 해야 알아듣는 놈이야.","JPN":"ウィルバーはそれくらい脅しておかないと、聞く耳を持たないからな。","ENG":"A threat like that is the only way to knock some sense into that Wilbur fool.","TWN":"對待韋爾伯那種傢伙，只有那麼說他才能聽得進去。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"뭐, 헛소리에 어울려 준 것치고는 제법 괜찮은 소득이었지.","JPN":"まあ、バカな夢物語に付き合ってやったわりには悪くない収穫だ。","ENG":"I guess humoring that crazy guy turned out to be more lucrative than expected.","TWN":"雖說是胡說嚇嚇他的，多虧他們也一本正經默默的接受了，收穫還算不錯。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"돌아간 후에 자기가 한 일을 반성한다면 연구비 정도는 챙겨줄 수도......","JPN":"戻った後、奴がやらかしたことを反省するなら研究費ぐらいは渡してあげても……","ENG":"If he shows any sign of remorse for what he's done, maybe I'll consider covering his research expenses...","TWN":"回去之後，如果他能對自己的所作所為好好反省，那我也可以支援一些研究費……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>......이리로 오라.</color>","JPN":"<color=#ff3636>……こちらへ来い。</color>","ENG":"<color=#ff3636>Come hither...</color>","TWN":"<color=#ff3636>……過來這裡。</color>"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......응?","JPN":"……ん？","ENG":"Huh?","TWN":"……嗯？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니? 왜 그래요?","JPN":"リタお姉ちゃん？　どうしたんですか？","ENG":"Rita? What is it?","TWN":"姐姐？你怎麼了？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"조용히 있어 봐. 방금 무슨 소리가 들렸어.","JPN":"静かに。声が聞こえた。","ENG":"Shh. I think I just heard something.","TWN":"安靜點，我剛剛好像聽到了什麼聲音。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"소리요? 저한테는 하나도 안 들렸는데?","JPN":"声ですか？　私には何も聞こえなかったですが……","ENG":"Heard what? I didn't hear anything.","TWN":"聲音？我怎麼什麼都沒聽到？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>우리의 자매가 될 자여. 이리로 오라.</color>","JPN":"<color=#ff3636>我が姉妹となる者よ。こちらへ来い。</color>","ENG":"<color=#ff3636>Ye who shall be our sister. Come hither.</color>","TWN":"<color=#ff3636>即將成為我們姐妹的人，過來吧。</color>"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이쪽인가?","JPN":"こっちか？","ENG":"Is it this way?","TWN":"是這邊嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};